// Created: 2026-07-17

/**
 * The load-bearing test for feat/session-title-regeneration: a regenerated
 * title must NEVER clobber an explicit /rename.
 *
 * shouldEmitSessionTitle is the single emission choke point. Before it emits a
 * CHANGED title it consults the transcript's last `custom-title` record; if the
 * user renamed (a title that is neither our last emit nor the git branch), it
 * suppresses. This is what lets regeneration coexist with /rename.
 *
 * Real filesystem (the guard reads a real transcript via openSync/readSync).
 */

import { afterEach, beforeEach, describe, expect, it } from 'vitest';
import { mkdtempSync, mkdirSync, rmSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { shouldEmitSessionTitle } from '../../prompt/unified-dispatcher.js';

let projectDir: string;
let transcript: string;
const SID = 'guard-session';

// getPromptSessionDir (no CLAUDE_PLUGIN_DATA) → <projectDir>/.claude/memory/sessions/<sid>.
function promptSessionDir(): string {
  return join(projectDir, '.claude', 'memory', 'sessions', SID);
}

function customTitleLine(title: string): string {
  return `${JSON.stringify({ type: 'custom-title', customTitle: title, sessionId: SID })}\n`;
}

beforeEach(() => {
  const root = mkdtempSync(join(tmpdir(), 'ork-rename-guard-'));
  projectDir = join(root, 'proj');
  mkdirSync(promptSessionDir(), { recursive: true });
  transcript = join(root, 'transcript.jsonl');
  writeFileSync(transcript, '', 'utf8');
});
afterEach(() => {
  rmSync(projectDir, { recursive: true, force: true });
});

/** Prime last-session-title.txt to simulate "we emitted this last turn". */
function primeLastEmitted(title: string): void {
  writeFileSync(join(promptSessionDir(), 'last-session-title.txt'), title, 'utf8');
}

describe('shouldEmitSessionTitle — /rename guard', () => {
  it('emits a changed title when the user has NOT renamed', () => {
    primeLastEmitted('📊 Old topic · feat/x');
    // transcript's last custom-title == what we emitted → no rename
    writeFileSync(transcript, customTitleLine('📊 Old topic · feat/x'), 'utf8');
    const emit = shouldEmitSessionTitle('🔧 New topic · feat/x', SID, projectDir, transcript, 'feat/x');
    expect(emit).toBe(true);
  });

  it('SUPPRESSES a changed title when the user HAS renamed (the core guarantee)', () => {
    primeLastEmitted('📊 Old topic · feat/x');
    // user renamed to something that is neither our last emit nor the branch
    writeFileSync(transcript, customTitleLine('my important session'), 'utf8');
    const emit = shouldEmitSessionTitle('🔧 New topic · feat/x', SID, projectDir, transcript, 'feat/x');
    expect(emit).toBe(false); // regeneration must not clobber the rename
  });

  it('does NOT treat a cmux branch stamp as a rename', () => {
    primeLastEmitted('📊 Old topic · feat/x');
    // cmux stamped the bare branch name as the live title
    writeFileSync(transcript, customTitleLine('feat/x'), 'utf8');
    const emit = shouldEmitSessionTitle('🔧 New topic · feat/x', SID, projectDir, transcript, 'feat/x');
    expect(emit).toBe(true); // branch stamp is not a manual rename → normal emit
  });

  it('returns false when the computed title is unchanged (existing delta-skip)', () => {
    primeLastEmitted('📊 Same · feat/x');
    writeFileSync(transcript, customTitleLine('anything'), 'utf8');
    const emit = shouldEmitSessionTitle('📊 Same · feat/x', SID, projectDir, transcript, 'feat/x');
    expect(emit).toBe(false); // unchanged → never emit, regardless of transcript
  });

  it('picks the LAST custom-title (most recent rename wins)', () => {
    primeLastEmitted('📊 Old · feat/x');
    writeFileSync(
      transcript,
      customTitleLine('📊 Old · feat/x') + customTitleLine('renamed once') + customTitleLine('renamed again'),
      'utf8',
    );
    const emit = shouldEmitSessionTitle('🔧 New · feat/x', SID, projectDir, transcript, 'feat/x');
    expect(emit).toBe(false); // latest record is a rename → suppress
  });
});
